sys_variable_value.value:
(function(outputs, steps, stepResult, assertEqual)
{
	var test = new x_snc_devtools.TestAPI(outputs, steps, stepResult, assertEqual);
	
	test.SetResult(true);

	if (GlidePluginManager.isActive('sn_genai_platform') == false)
	{
		test.Log('Plugin sn_genai_platform is not available.');
		return test.GetResult();
	}
	
	var strCheck = '7178e5a73b1f3a1062bf612c95e45ad1';
	
	// Findings are only generated if there are more than one agent in the app scope
	var grAgent = new GlideRecord('sn_aia_agent');
	grAgent.initialize();
	grAgent.sys_scope = 'global';
	grAgent.name = 'ATF Agent 0';
	grAgent.description = 'A description.';
	var strAgentSysId = x_snc_devtools.GlideRecordInsert(grAgent);

	var grAgent = new GlideRecord('sn_aia_agent');
	grAgent.initialize();
	grAgent.sys_scope = 'global';
	grAgent.name = 'ATF Agent 1';
	grAgent.description = 'A description.';
	var strAgentSysId = x_snc_devtools.GlideRecordInsert(grAgent);

	var grTool = new GlideRecord('sn_aia_tool');
	grTool.initialize();
	grTool.sys_scope = 'global';
	grTool.name = 'ATF Tool 1';
	grTool.description = 'A description.';
	var strToolSysId = x_snc_devtools.GlideRecordInsert(grTool);

	var grRecord = new GlideRecord('sn_aia_agent_tool_m2m');
	grRecord.initialize();
	grRecord.agent = strAgentSysId;
	grRecord.tool = strToolSysId;
	grRecord.description = 'This is a test';
	grRecord.name = 'This name is not compliant';
	grRecord.sys_scope = 'global';
	var strRecordSysId = x_snc_devtools.GlideRecordInsert(grRecord);

	// Agent Tool is now associated to an agent and a tool - but the tool does not comply with the naming convention
	test.TestCase_InstanceScanCheck(strCheck,'sn_aia_agent_tool_m2m',strRecordSysId,true);
	
	x_snc_devtools.RecordSetValue('sn_aia_tool',strToolSysId,'name','ATF Agent 1 - ATF Tool 1');

	// The Tool is now named correctly, but the Agent Tool is not yet
	test.TestCase_InstanceScanCheck(strCheck,'sn_aia_agent_tool_m2m',strRecordSysId,true);

	x_snc_devtools.RecordSetValue('sn_aia_agent_tool_m2m',strRecordSysId,'name','ATF Agent 1 - ATF Tool 1');

	test.Log(x_snc_devtools.GetRecord('sn_aia_agent',strAgentSysId));
	test.Log(x_snc_devtools.GetRecord('sn_aia_tool',strToolSysId));
	test.Log(x_snc_devtools.GetRecord('sn_aia_agent_tool_m2m',strRecordSysId));


	// All is fine now
	test.TestCase_InstanceScanCheck(strCheck,'sn_aia_agent_tool_m2m',strRecordSysId,false);


	
	return test.GetResult();
	
})(outputs, steps, stepResult, assertEqual);
